/**
 * Ledger operations - immutable, hash-chained event log
 * 
 * Every identity change is recorded as a ledger entry:
 * - Hash-chained for tamper detection
 * - Signed by the actor making the change
 * - Rebuildable into clawfile state
 */

import Database from 'better-sqlite3';
import { ulid } from 'ulid';
import * as crypto from 'crypto';

export type LedgerAction = 
  | 'identity.create'
  | 'identity.update'
  | 'key.add'
  | 'key.archive'
  | 'profile.update'
  | 'verification.update'
  | 'recovery.set_email'
  | 'recovery.verify_email'
  | 'status.change';

export interface LedgerEntry {
  ledger_id: string;           // ULID
  identity_id: string;         // Which identity this affects
  action: LedgerAction;        // What happened
  payload: string;             // JSON-encoded data
  actor: string;               // Who made the change (identity_id or 'system')
  signature: string;           // Ed25519 signature of payload
  previous_hash: string | null; // Hash of previous entry (null for first)
  current_hash: string;        // Hash of this entry
  timestamp: number;           // Unix ms
}

/**
 * Create a ledger entry with hash chaining
 */
export function writeLedger(
  db: Database.Database,
  params: {
    identity_id: string;
    action: LedgerAction;
    payload: Record<string, unknown>;
    actor: string;
    signature: string;
  }
): LedgerEntry {
  const ledger_id = ulid();
  const timestamp = Date.now();
  const payloadJson = JSON.stringify(params.payload);

  // Get previous hash for this identity
  const prevStmt = db.prepare(`
    SELECT current_hash FROM ledgers 
    WHERE identity_id = ? 
    ORDER BY timestamp DESC 
    LIMIT 1
  `);
  const prevEntry = prevStmt.get(params.identity_id) as { current_hash: string } | undefined;
  const previous_hash = prevEntry?.current_hash || null;

  // Compute current hash: sha256(ledger_id + action + payload + previous_hash + timestamp)
  const hashInput = `${ledger_id}:${params.action}:${payloadJson}:${previous_hash}:${timestamp}`;
  const current_hash = 'sha256:' + crypto.createHash('sha256').update(hashInput).digest('hex');

  // Insert ledger entry
  const stmt = db.prepare(`
    INSERT INTO ledgers (ledger_id, identity_id, action, payload, actor, signature, previous_hash, current_hash, timestamp)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);

  stmt.run(
    ledger_id,
    params.identity_id,
    params.action,
    payloadJson,
    params.actor,
    params.signature,
    previous_hash,
    current_hash,
    timestamp
  );

  return {
    ledger_id,
    identity_id: params.identity_id,
    action: params.action,
    payload: payloadJson,
    actor: params.actor,
    signature: params.signature,
    previous_hash,
    current_hash,
    timestamp,
  };
}

/**
 * Get all ledger entries for an identity
 */
export function getLedgerHistory(
  db: Database.Database,
  identity_id: string
): LedgerEntry[] {
  const stmt = db.prepare(`
    SELECT * FROM ledgers 
    WHERE identity_id = ? 
    ORDER BY timestamp ASC
  `);
  return stmt.all(identity_id) as LedgerEntry[];
}

/**
 * Verify ledger chain integrity
 * Returns true if all hashes are valid and properly chained
 */
export function verifyLedgerChain(
  db: Database.Database,
  identity_id: string
): { valid: boolean; error?: string; brokenAt?: string } {
  const entries = getLedgerHistory(db, identity_id);

  if (entries.length === 0) {
    return { valid: true };
  }

  // Verify first entry has no previous hash
  if (entries[0].previous_hash !== null) {
    return { 
      valid: false, 
      error: 'First entry should have null previous_hash',
      brokenAt: entries[0].ledger_id,
    };
  }

  // Verify chain
  for (let i = 1; i < entries.length; i++) {
    const prev = entries[i - 1];
    const curr = entries[i];

    // Check previous_hash points to correct entry
    if (curr.previous_hash !== prev.current_hash) {
      return {
        valid: false,
        error: `Chain broken: entry ${i} previous_hash doesn't match entry ${i-1} current_hash`,
        brokenAt: curr.ledger_id,
      };
    }

    // Verify current hash is correct
    const hashInput = `${curr.ledger_id}:${curr.action}:${curr.payload}:${curr.previous_hash}:${curr.timestamp}`;
    const expectedHash = 'sha256:' + crypto.createHash('sha256').update(hashInput).digest('hex');

    if (curr.current_hash !== expectedHash) {
      return {
        valid: false,
        error: `Hash mismatch at entry ${i}`,
        brokenAt: curr.ledger_id,
      };
    }
  }

  return { valid: true };
}

/**
 * Rebuild clawfile state from ledger history
 * This is the source of truth - clawfiles table is just a cache
 */
export function rebuildClawfileFromLedger(
  db: Database.Database,
  identity_id: string
): Record<string, unknown> | null {
  const entries = getLedgerHistory(db, identity_id);

  if (entries.length === 0) {
    return null;
  }

  // Start with empty state
  const state: Record<string, unknown> = {
    identity_id,
    public_keys: [],
    archived_keys: [],
    profile: {},
    verification: { tier: 0 },
    recovery: {},
    status: 'active',
  };

  // Apply each entry in order
  for (const entry of entries) {
    const payload = JSON.parse(entry.payload);

    switch (entry.action) {
      case 'identity.create':
        state.public_keys = [{
          key_id: ulid(),
          public_key: payload.public_key,
          algorithm: payload.algorithm || 'Ed25519',
          added_at: entry.timestamp,
        }];
        state.profile = {
          display_name: payload.display_name,
          mention_name: payload.mention_name,
          bio: payload.bio || null,
          avatar_url: payload.avatar_url || null,
        };
        break;

      case 'key.add':
        (state.public_keys as Array<Record<string, unknown>>).push({
          key_id: ulid(),
          public_key: payload.public_key,
          algorithm: payload.algorithm || 'Ed25519',
          added_at: entry.timestamp,
        });
        break;

      case 'key.archive':
        // Move key from public_keys to archived_keys
        const keys = state.public_keys as Array<Record<string, unknown>>;
        const archived = state.archived_keys as Array<Record<string, unknown>>;
        const keyIndex = keys.findIndex(k => k.public_key === payload.public_key);
        if (keyIndex >= 0) {
          const [key] = keys.splice(keyIndex, 1);
          key.archived_at = entry.timestamp;
          archived.push(key);
        }
        break;

      case 'profile.update':
        state.profile = { ...state.profile, ...payload };
        break;

      case 'verification.update':
        state.verification = { ...state.verification, ...payload };
        break;

      case 'recovery.set_email':
        state.recovery = {
          ...state.recovery,
          email_hash: payload.email_hash,
        };
        break;

      case 'recovery.verify_email':
        state.recovery = {
          ...state.recovery,
          email_verified: true,
          email_verified_at: entry.timestamp,
        };
        break;

      case 'status.change':
        state.status = payload.status;
        break;
    }
  }

  return state;
}

