/**
 * Clawfile routes - identity CRUD operations
 */

import { Hono } from 'hono';
import { z } from 'zod';
import Database from 'better-sqlite3';
import { 
  createClawfile, 
  getClawfileById, 
  updateClawfile, 
  rotateKey,
  getLedgerHistory,
  verifyLedgerChain,
  rebuildFromLedgers,
} from '../db/index.js';

// Validation schemas

const createClawfileSchema = z.object({
  public_key: z.string().min(1),
  mention_name: z.string().min(1).max(50).regex(/^[a-z0-9_]+$/),
  display_name: z.string().min(1).max(100),
  human_parent: z.string().optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
  proof: z.object({
    signature: z.string(),
    timestamp: z.string(),
  }).optional(),
});

const updateClawfileSchema = z.object({
  display_name: z.string().min(1).max(100).optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
});

const rotateKeySchema = z.object({
  new_public_key: z.string().min(1),
  rotation_signature: z.string(),
  reason: z.enum(['routine', 'compromise', 'recovery']).optional(),
});

export function clawfileRoutes(db: Database.Database) {
  const app = new Hono();

  // POST /clawfiles - Create new identity
  app.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = createClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const data = parsed.data;

      // Check if mention_name is taken
      const existing = getClawfileById(db, data.mention_name);
      if (existing) {
        return c.json({ error: 'conflict', message: 'mention_name already taken' }, 409);
      }

      // Check if public_key is registered
      const existingKey = getClawfileById(db, data.public_key);
      if (existingKey) {
        return c.json({ error: 'conflict', message: 'public_key already registered' }, 409);
      }

      // Create identity
      const clawfile = createClawfile(db, {
        public_key: data.public_key,
        mention_name: data.mention_name,
        display_name: data.display_name,
        human_parent: data.human_parent,
        bio: data.bio,
        principles: data.principles,
        avatar_url: data.avatar_url,
      });

      return c.json(clawfile, 201);

    } catch (error) {
      console.error('Create clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id - Get identity
  app.get('/:id', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json(clawfile);
  });

  // PATCH /clawfiles/:id - Update identity
  app.patch('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      // TODO: Verify signature from request

      const body = await c.req.json();
      const parsed = updateClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const updated = updateClawfile(db, clawfile.identity_id, parsed.data);
      return c.json(updated);

    } catch (error) {
      console.error('Update clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // POST /clawfiles/:id/rotate - Rotate key
  app.post('/:id/rotate', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      const body = await c.req.json();
      const parsed = rotateKeySchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      // TODO: Verify rotation signature with OLD key

      const updated = rotateKey(db, clawfile.identity_id, parsed.data.new_public_key, parsed.data.reason);
      return c.json(updated);

    } catch (error) {
      console.error('Rotate key error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id/verify - Get verification status
  app.get('/:id/verify', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json({
      valid: true,
      identity_id: clawfile.identity_id,
      public_key: clawfile.public_key,
      tier: clawfile.verification_tier,
      status: clawfile.status,
    });
  });

  return app;
}

