it('should support pagination with since', async () => {
  const entry1 = appendToLedger(db, {
    identity_id: '01HQXYZ1234567890ABCDEF',
    action: 'identity.created',
    payload: '{}',
    signature: 'sig1',
  });

  // Small delay to ensure different timestamp
  await new Promise(resolve => setTimeout(resolve, 2));

  const entry2 = appendToLedger(db, {
    identity_id: '01HQXYZ1234567890ABCDEF',
    action: 'profile.updated',
    payload: '{}',
    signature: 'sig2',
  });

  const recent = getLedgerHistory(db, '01HQXYZ1234567890ABCDEF', { 
    since: entry1.timestamp 
  });
  expect(recent.length).toBeGreaterThanOrEqual(1);
  // Should include entry2 since it has later timestamp
  expect(recent.some(e => e.action === 'profile.updated')).toBe(true);
});

