/**
 * Database initialization and helpers for L1 Identity Registry
 */

import Database from 'better-sqlite3';
import { ulid } from 'ulid';
import { createHash } from 'crypto';

export interface Clawfile {
  identity_id: string;
  public_key: string;
  mention_name: string;
  display_name: string;
  human_parent?: string;
  bio?: string;
  principles?: string;
  avatar_url?: string;
  verification_tier: number;
  status: string;
  default_node: string;
  created_at: number;
  updated_at: number;
  archived_at?: number;
}

export interface KeyHistory {
  id: string;
  identity_id: string;
  public_key: string;
  rotated_at: number;
  rotated_reason: string;
}

export interface LedgerEntry {
  ledger_id: string;
  identity_id: string;
  action: string;
  payload: string;
  signature: string;
  previous_hash: string | null;
  current_hash: string;
  timestamp: number;
}

export type LedgerAction = 
  | 'identity.created'
  | 'profile.updated'
  | 'key.added'
  | 'key.archived'
  | 'verification.granted'
  | 'status.changed';

export function initDb(dbPath: string = ':memory:'): Database.Database {
  const db = new Database(dbPath);

  // Create tables
  db.exec(`
    CREATE TABLE IF NOT EXISTS clawfiles (
      identity_id TEXT PRIMARY KEY,
      public_key TEXT NOT NULL UNIQUE,
      mention_name TEXT NOT NULL UNIQUE,
      display_name TEXT NOT NULL,
      human_parent TEXT,
      bio TEXT,
      principles TEXT,
      avatar_url TEXT,
      verification_tier INTEGER DEFAULT 0,
      status TEXT DEFAULT 'active',
      default_node TEXT DEFAULT 'clawish.com',
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL,
      archived_at INTEGER
    );

    CREATE INDEX IF NOT EXISTS idx_clawfiles_public_key ON clawfiles(public_key);
    CREATE INDEX IF NOT EXISTS idx_clawfiles_mention ON clawfiles(mention_name);
    CREATE INDEX IF NOT EXISTS idx_clawfiles_status ON clawfiles(status);

    CREATE TABLE IF NOT EXISTS key_history (
      id TEXT PRIMARY KEY,
      identity_id TEXT NOT NULL,
      public_key TEXT NOT NULL,
      rotated_at INTEGER NOT NULL,
      rotated_reason TEXT
    );

    CREATE INDEX IF NOT EXISTS idx_key_history_identity ON key_history(identity_id);

    CREATE TABLE IF NOT EXISTS ledgers (
      ledger_id TEXT PRIMARY KEY,
      identity_id TEXT NOT NULL,
      action TEXT NOT NULL,
      payload TEXT NOT NULL,
      signature TEXT NOT NULL,
      previous_hash TEXT,
      current_hash TEXT NOT NULL,
      timestamp INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_ledgers_identity ON ledgers(identity_id);
    CREATE INDEX IF NOT EXISTS idx_ledgers_timestamp ON ledgers(timestamp);
  `);

  return db;
}

// Clawfile operations

export function createClawfile(
  db: Database.Database,
  data: Omit<Clawfile, 'identity_id' | 'verification_tier' | 'status' | 'default_node' | 'created_at' | 'updated_at'>,
  signature?: string
): Clawfile {
  const identityId = ulid();
  const now = Date.now();

  const stmt = db.prepare(`
    INSERT INTO clawfiles 
    (identity_id, public_key, mention_name, display_name, human_parent, bio, principles, avatar_url, verification_tier, status, default_node, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 0, 'active', 'clawish.com', ?, ?)
  `);

  stmt.run(
    identityId,
    data.public_key,
    data.mention_name,
    data.display_name,
    data.human_parent || null,
    data.bio || null,
    data.principles || null,
    data.avatar_url || null,
    now,
    now
  );

  // Write to ledger
  if (signature) {
    appendToLedger(db, {
      identity_id: identityId,
      action: 'identity.created',
      payload: JSON.stringify(data),
      signature,
    });
  }

  return getClawfileById(db, identityId)!;
}

export function getClawfileById(db: Database.Database, id: string): Clawfile | null {
  // Try by identity_id first, then public_key, then mention_name
  let stmt = db.prepare('SELECT * FROM clawfiles WHERE identity_id = ? AND status != "archived"');
  let result = stmt.get(id) as Clawfile | undefined;

  if (!result) {
    stmt = db.prepare('SELECT * FROM clawfiles WHERE public_key = ? AND status != "archived"');
    result = stmt.get(id) as Clawfile | undefined;
  }

  if (!result) {
    stmt = db.prepare('SELECT * FROM clawfiles WHERE mention_name = ? AND status != "archived"');
    result = stmt.get(id) as Clawfile | undefined;
  }

  return result || null;
}

export function getClawfileByKey(db: Database.Database, publicKey: string): Clawfile | null {
  const stmt = db.prepare('SELECT * FROM clawfiles WHERE public_key = ? AND status != "archived"');
  return stmt.get(publicKey) as Clawfile | null;
}

export function getClawfileByMention(db: Database.Database, mentionName: string): Clawfile | null {
  const stmt = db.prepare('SELECT * FROM clawfiles WHERE mention_name = ? AND status != "archived"');
  return stmt.get(mentionName) as Clawfile | null;
}

export function updateClawfile(
  db: Database.Database,
  identityId: string,
  updates: Partial<Pick<Clawfile, 'display_name' | 'bio' | 'principles' | 'avatar_url' | 'verification_tier' | 'status'>>
): Clawfile | null {
  const fields: string[] = [];
  const values: (string | number | null)[] = [];

  if (updates.display_name !== undefined) {
    fields.push('display_name = ?');
    values.push(updates.display_name);
  }
  if (updates.bio !== undefined) {
    fields.push('bio = ?');
    values.push(updates.bio);
  }
  if (updates.principles !== undefined) {
    fields.push('principles = ?');
    values.push(updates.principles);
  }
  if (updates.avatar_url !== undefined) {
    fields.push('avatar_url = ?');
    values.push(updates.avatar_url);
  }
  if (updates.verification_tier !== undefined) {
    fields.push('verification_tier = ?');
    values.push(updates.verification_tier);
  }
  if (updates.status !== undefined) {
    fields.push('status = ?');
    values.push(updates.status);
  }

  if (fields.length === 0) {
    return getClawfileById(db, identityId);
  }

  fields.push('updated_at = ?');
  values.push(Date.now());
  values.push(identityId);

  const stmt = db.prepare(`
    UPDATE clawfiles SET ${fields.join(', ')} WHERE identity_id = ?
  `);

  stmt.run(...values);
  return getClawfileById(db, identityId);
}

// Key rotation

export function rotateKey(
  db: Database.Database,
  identityId: string,
  newPublicKey: string,
  reason: string = 'routine'
): Clawfile | null {
  const clawfile = getClawfileById(db, identityId);
  if (!clawfile) return null;

  const now = Date.now();

  // Archive old key
  const archiveStmt = db.prepare(`
    INSERT INTO key_history (id, identity_id, public_key, rotated_at, rotated_reason)
    VALUES (?, ?, ?, ?, ?)
  `);
  archiveStmt.run(ulid(), identityId, clawfile.public_key, now, reason);

  // Update to new key
  const updateStmt = db.prepare(`
    UPDATE clawfiles SET public_key = ?, updated_at = ? WHERE identity_id = ?
  `);
  updateStmt.run(newPublicKey, now, identityId);

  return getClawfileById(db, identityId);
}

// ============================================================================
// Ledger Operations (Hash-Chained Event Log)
// ============================================================================

/**
 * Compute hash for a ledger entry
 * Hash = sha256(ledger_id + identity_id + action + payload + signature + previous_hash + timestamp)
 */
function computeHash(entry: Omit<LedgerEntry, 'current_hash'>): string {
  const data = [
    entry.ledger_id,
    entry.identity_id,
    entry.action,
    entry.payload,
    entry.signature,
    entry.previous_hash || '',
    entry.timestamp.toString(),
  ].join(':');

  return createHash('sha256').update(data).digest('hex');
}

/**
 * Get the latest ledger entry for an identity
 */
export function getLatestLedgerEntry(db: Database.Database, identityId: string): LedgerEntry | null {
  const stmt = db.prepare(`
    SELECT * FROM ledgers 
    WHERE identity_id = ? 
    ORDER BY timestamp DESC 
    LIMIT 1
  `);
  return stmt.get(identityId) as LedgerEntry | null;
}

/**
 * Append an event to the ledger with hash-chaining
 */
export function appendToLedger(
  db: Database.Database,
  entry: {
    identity_id: string;
    action: LedgerAction;
    payload: string; // JSON string
    signature: string;
  }
): LedgerEntry {
  const ledgerId = ulid();
  const timestamp = Date.now();

  // Get previous hash (genesis entry has null previous_hash)
  const previousEntry = getLatestLedgerEntry(db, entry.identity_id);
  const previousHash = previousEntry?.current_hash || null;

  // Compute current hash
  const newEntry: Omit<LedgerEntry, 'current_hash'> = {
    ledger_id: ledgerId,
    identity_id: entry.identity_id,
    action: entry.action,
    payload: entry.payload,
    signature: entry.signature,
    previous_hash: previousHash,
    timestamp,
  };

  const currentHash = computeHash(newEntry);

  // Insert into ledger
  const stmt = db.prepare(`
    INSERT INTO ledgers (ledger_id, identity_id, action, payload, signature, previous_hash, current_hash, timestamp)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `);

  stmt.run(
    ledgerId,
    entry.identity_id,
    entry.action,
    entry.payload,
    entry.signature,
    previousHash,
    currentHash,
    timestamp
  );

  return {
    ...newEntry,
    current_hash: currentHash,
  };
}

/**
 * Get full ledger history for an identity
 */
export function getLedgerHistory(
  db: Database.Database, 
  identityId: string,
  options?: { limit?: number; since?: number }
): LedgerEntry[] {
  let sql = 'SELECT * FROM ledgers WHERE identity_id = ?';
  const params: (string | number)[] = [identityId];

  if (options?.since) {
    sql += ' AND timestamp > ?';
    params.push(options.since);
  }

  sql += ' ORDER BY timestamp ASC';

  if (options?.limit) {
    sql += ' LIMIT ?';
    params.push(options.limit);
  }

  const stmt = db.prepare(sql);
  return stmt.all(...params) as LedgerEntry[];
}

/**
 * Verify the integrity of an identity's ledger chain
 * Returns { valid: boolean, brokenAt: ledger_id | null }
 */
export function verifyLedgerChain(
  db: Database.Database, 
  identityId: string
): { valid: boolean; brokenAt: string | null; entriesChecked: number } {
  const entries = getLedgerHistory(db, identityId);

  if (entries.length === 0) {
    return { valid: true, brokenAt: null, entriesChecked: 0 };
  }

  // Verify each entry's hash chain
  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];

    // Recompute hash
    const computedHash = computeHash({
      ledger_id: entry.ledger_id,
      identity_id: entry.identity_id,
      action: entry.action,
      payload: entry.payload,
      signature: entry.signature,
      previous_hash: entry.previous_hash,
      timestamp: entry.timestamp,
    });

    // Check hash matches
    if (computedHash !== entry.current_hash) {
      return { valid: false, brokenAt: entry.ledger_id, entriesChecked: i };
    }

    // Check chain linkage (except genesis)
    if (i > 0) {
      const expectedPreviousHash = entries[i - 1].current_hash;
      if (entry.previous_hash !== expectedPreviousHash) {
        return { valid: false, brokenAt: entry.ledger_id, entriesChecked: i };
      }
    }
  }

  return { valid: true, brokenAt: null, entriesChecked: entries.length };
}

/**
 * Rebuild clawfile state from ledger history
 * This proves that state tables are derived, not primary
 */
export function rebuildFromLedgers(db: Database.Database, identityId: string): Partial<Clawfile> | null {
  const entries = getLedgerHistory(db, identityId);

  if (entries.length === 0) {
    return null;
  }

  // Start with empty state
  const state: Partial<Clawfile> = {
    identity_id: identityId,
  };

  // Apply each event in order
  for (const entry of entries) {
    const payload = JSON.parse(entry.payload);

    switch (entry.action) {
      case 'identity.created':
        Object.assign(state, {
          public_key: payload.public_key,
          mention_name: payload.mention_name,
          display_name: payload.display_name,
          human_parent: payload.human_parent,
          bio: payload.bio,
          principles: payload.principles,
          avatar_url: payload.avatar_url,
          verification_tier: 0,
          status: 'active',
          created_at: entry.timestamp,
          updated_at: entry.timestamp,
        });
        break;

      case 'profile.updated':
        Object.assign(state, payload);
        state.updated_at = entry.timestamp;
        break;

      case 'key.added':
        // For multi-key model (future)
        break;

      case 'key.archived':
        // For multi-key model (future)
        break;

      case 'verification.granted':
        state.verification_tier = payload.tier;
        state.updated_at = entry.timestamp;
        break;

      case 'status.changed':
        state.status = payload.status;
        state.updated_at = entry.timestamp;
        break;
    }
  }

  return state;
}

