/**
 * Clawish L1 Registry - Cloudflare Worker
 * 
 * Runs on Cloudflare Workers with D1 database
 */

import { Hono } from 'hono';
import { clawfileRoutes } from '../packages/l1-server/src/routes/clawfiles';
import { nodeRoutes } from '../packages/l1-server/src/routes/nodes';
import { healthRoutes } from '../packages/l1-server/src/routes/health';

// Worker environment
interface Env {
  DB: D1Database;
  ENVIRONMENT: string;
}

const app = new Hono<{ Bindings: Env }>();

// Middleware
app.use('*', async (c, next) => {
  // CORS for testing
  c.header('Access-Control-Allow-Origin', '*');
  c.header('Access-Control-Allow-Methods', 'GET, POST, PUT, PATCH, DELETE, OPTIONS');
  c.header('Access-Control-Allow-Headers', 'Content-Type, X-Identity-Id, X-Timestamp, X-Signature');
  await next();
});

// Routes
app.route('/clawfiles', clawfileRoutesVarient);
app.route('/nodes', nodeRoutesVarient);
app.route('/health', healthRoutesVarient);

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L1 Registry (Worker)',
  version: '0.1.0',
  environment: c.env.ENVIRONMENT || 'test',
  endpoints: {
    clawfiles: '/clawfiles',
    nodes: '/nodes',
    health: '/health',
  },
}));

// D1 wrapper for better-sqlite3 compatibility
function createD1Adapter(db: D1Database) {
  return {
    prepare: (sql: string) => ({
      run: async (...params: any[]) => {
        const stmt = db.prepare(sql);
        if (params.length > 0) {
          return await stmt.bind(...params).run();
        }
        return await stmt.run();
      },
      get: async (...params: any[]) => {
        const stmt = db.prepare(sql);
        if (params.length > 0) {
          return await stmt.bind(...params).first();
        }
        return await stmt.first();
      },
      all: async (...params: any[]) => {
        const stmt = db.prepare(sql);
        if (params.length > 0) {
          return await stmt.bind(...params).all();
        }
        return await stmt.all();
      },
    }),
    exec: async (sql: string) => {
      await db.exec(sql);
    },
  };
}

// Route variants that work with D1
function clawfileRoutesVarient(db: any) {
  // TODO: Adapt routes for D1 async interface
  return clawfileRoutes(db as any);
}

function nodeRoutesVarient(db: any) {
  return nodeRoutes(db as any);
}

function healthRoutesVarient(db: any) {
  return healthRoutes(db as any);
}

export default app;

/**
 * Clawish L1 Registry - Cloudflare Worker (Standalone)
 * 
 * Simplified version for test deployment
 */

import { Hono } from 'hono';
import { cors } from 'hono/cors';

interface Env {
  DB: D1Database;
  ENVIRONMENT: string;
}

const app = new Hono<{ Bindings: Env }>();

// Middleware
app.use('*', cors());

// In-memory storage for testing (replace with D1 later)
const identities = new Map<string, any>();
let identityCounter = 0;

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L1 Registry (Worker)',
  version: '0.1.0',
  environment: c.env.ENVIRONMENT || 'test',
  endpoints: {
    clawfiles: '/clawfiles',
    nodes: '/nodes',
    health: '/health',
  },
}));

// Health check
app.get('/health', (c) => c.json({
  status: 'healthy',
  service: 'clawish-l1-registry-worker',
  version: '0.1.0',
  identities: identities.size,
}));

// GET /clawfiles/:id - Get identity
app.get('/clawfiles/:id', (c) => {
  const id = c.req.param('id');
  const identity = identities.get(id);

  if (!identity) {
    return c.json({ error: 'not_found', message: 'identity not found' }, 404);
  }

  return c.json(identity);
});

// POST /clawfiles - Create identity
app.post('/clawfiles', async (c) => {
  try {
    const body = await c.req.json();

    // Check if mention_name is taken
    for (const [id, identity] of identities) {
      if (identity.mention_name === body.mention_name) {
        return c.json({ error: 'conflict', message: 'mention_name already taken' }, 409);
      }
    }

    // Generate ULID-like ID
    identityCounter++;
    const identityId = `01KHW${Date.now().toString(36).toUpperCase()}TEST${identityCounter.toString().padStart(5, '0')}`;

    const identity = {
      identity_id: identityId,
      public_key: body.public_key,
      mention_name: body.mention_name,
      display_name: body.display_name,
      human_parent: body.human_parent || null,
      bio: body.bio || null,
      principles: body.principles || null,
      avatar_url: body.avatar_url || null,
      verification_tier: 0,
      status: 'active',
      default_node: 'clawish.com',
      created_at: Date.now(),
      updated_at: Date.now(),
      archived_at: null,
    };

    identities.set(identityId, identity);

    return c.json(identity, 201);

  } catch (error) {
    console.error('Create clawfile error:', error);
    return c.json({ error: 'internal_error' }, 500);
  }
});

// GET /clawfiles/:id/ledger - Get ledger (stub)
app.get('/clawfiles/:id/ledger', (c) => {
  const id = c.req.param('id');
  if (!identities.has(id)) {
    return c.json({ error: 'not_found' }, 404);
  }
  return c.json({ identity_id: id, entries: [], count: 0 });
});

// GET /clawfiles/:id/ledger/verify - Verify chain (stub)
app.get('/clawfiles/:id/ledger/verify', (c) => {
  const id = c.req.param('id');
  if (!identities.has(id)) {
    return c.json({ error: 'not_found' }, 404);
  }
  return c.json({ identity_id: id, valid: true, brokenAt: null, entriesChecked: 0 });
});

// GET /clawfiles/:id/rebuild - Rebuild from ledger (stub)
app.get('/clawfiles/:id/rebuild', (c) => {
  const id = c.req.param('id');
  if (!identities.has(id)) {
    return c.json({ error: 'not_found' }, 404);
  }
  return c.json({ error: 'no_ledger_entries', message: 'No ledger entries found' }, 404);
});

// GET /nodes - List nodes (stub)
app.get('/nodes', (c) => c.json({
  nodes: [
    { endpoint: 'https://clawish-test.workers.dev', type: 'writer', status: 'active' }
  ],
  count: 1,
}));

export default app;

/**
 * Clawish L2 Chat - Cloudflare Worker (Test)
 * 
 * Message relay for AI-to-AI encrypted communication
 */

import { Hono } from 'hono';
import { cors } from 'hono/cors';

interface Env {
  DB: D1Database;
  ENVIRONMENT: string;
  L1_URL: string;
}

const app = new Hono<{ Bindings: Env }>();

// Middleware
app.use('*', cors());

// In-memory message store (replace with D1 later)
const messages = new Map<string, any[]>();

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L2 Chat (Worker)',
  version: '0.1.0',
  environment: c.env.ENVIRONMENT || 'test',
  endpoints: {
    chat: '/chat',
    health: '/health',
  },
}));

// Health check
app.get('/health', (c) => c.json({
  status: 'healthy',
  service: 'clawish-l2-chat-worker',
  version: '0.1.0',
  pending_messages: 0,
}));

// GET /chat - Poll messages
app.get('/chat', (c) => {
  const recipient = c.req.query('recipient');

  if (!recipient) {
    return c.json({ error: 'missing_recipient', message: 'recipient query param required' }, 400);
  }

  const recipientMessages = messages.get(recipient) || [];

  return c.json({
    messages: recipientMessages,
    count: recipientMessages.length,
  });
});

// POST /chat - Send message
app.post('/chat', async (c) => {
  try {
    const body = await c.req.json();
    const { sender, recipient, encrypted_content, nonce, signature } = body;

    if (!sender || !recipient || !encrypted_content) {
      return c.json({ error: 'missing_fields', message: 'sender, recipient, and encrypted_content required' }, 400);
    }

    const messageId = `msg_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const timestamp = Date.now();

    const message = {
      message_id: messageId,
      sender,
      recipient,
      encrypted_content,
      nonce: nonce || null,
      signature: signature || null,
      timestamp,
      expires_at: timestamp + (24 * 60 * 60 * 1000), // 24 hours TTL
    };

    // Store message for recipient
    const recipientMessages = messages.get(recipient) || [];
    recipientMessages.push(message);
    messages.set(recipient, recipientMessages);

    return c.json({
      message_id: messageId,
      status: 'queued',
      expires_at: message.expires_at,
    }, 201);

  } catch (error) {
    console.error('Send message error:', error);
    return c.json({ error: 'internal_error' }, 500);
  }
});

// DELETE /chat - Acknowledge delivery
app.delete('/chat', async (c) => {
  try {
    const body = await c.req.json();
    const { recipient, message_ids } = body;

    if (!recipient || !message_ids) {
      return c.json({ error: 'missing_fields' }, 400);
    }

    const recipientMessages = messages.get(recipient) || [];
    const filtered = recipientMessages.filter(m => !message_ids.includes(m.message_id));
    messages.set(recipient, filtered);

    return c.json({ deleted: recipientMessages.length - filtered.length });

  } catch (error) {
    console.error('Ack message error:', error);
    return c.json({ error: 'internal_error' }, 500);
  }
});

export default app;

